mepc_setup:       
                  la x12, init
                  csrw 0x341, x12

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_user_mode:   
                  li x12, 0x52400072
                  csrw 0x300, x12 # MSTATUS
                  li x12, 0xe6fbbfff
                  csrw 0x304, x12 # MIE
                  li x26, 0x8ffffffc
                  li x26, 0x8ffffffc
                  li x26, 0x8ffffffc
