                  li x29, 0xa
                  li x31, 0xfe7ee8c7
                  la x9, user_stack_end
                  li x26, 0x8ffffffc
                  li x12, 0x0
                  slli x12, x12, 8
                  addi x12, x12, 0x0
                  sw x12, 0(x26)
                  j main
test_done:        
                  li x26, 0x8ffffff8
                  li x12, 0x0
                  slli x12, x12, 8
                  addi x12, x12, 0x1
                  sw x12, 0(x26)
                  ecall

